    private var timer: Timer?
    private let warningDuration: TimeInterval  // Default: 90 * 60 (90 minutes)
    private var hasShownWarning = false
    var onProlongedSession: (() -> Void)?

    var isOlderDevice: Bool {
        ProcessInfo.processInfo.physicalMemory < 3 * 1024 * 1024 * 1024
